/**
 * Tunable params for the ChangeOrderPanelOrbital orbital.
 *
 * Canonical entity: ChangeOrder — overridable via
 * `entityName`. The factory threads the effective name through every
 * trait's `linkedEntity` binding; the `.orb` compiler's inline phase
 * auto-rewrites every `@Entity.x`, `["ref",X]`, `["fetch",X,…]`,
 * `["persist",…,X,…]` and payload type string accordingly.
 *
 * Override surface (mirrors `.lolo`'s native overrides 1:1):
 *   fields         — extra entity fields (appended)
 *   pagePath       — first-page URL override
 *   persistence    — entity persistence mode
 *   entityName     — rename the canonical entity
 *   collection     — override the derived collection key
 *   traitOverrides — per-imported-trait `config`, `linkedEntity`,
 *                    `events`, `name`, `emitsScope`, `listens`.
 *                    `effects` is NOT exposed — `.lolo` removed it
 *                    in Phase 9.5.H. Use `listens` via a sibling
 *                    trait to react to atom events.
 */
export interface StdConstructionPmChangeOrderPanelOrbitalParams {
  /** Extra fields appended to the canonical entity. */
  fields?: EntityField[];
  /** URL path override for the orbital's first page. */
  pagePath?: string;
  /** Override the canonical entity persistence mode. */
  persistence?: EntityPersistence;
  /** Rename the canonical entity (PascalCase singular, ≤32 chars). */
  entityName?: string;
  /** Override derived collection key (defaults to plural(entityName).toLowerCase()). */
  collection?: string;
  /**
   * Per-imported-trait override surface keyed on each imported
   * trait's canonical `name`. Accepts every override `.lolo`
   * natively supports: `config`, `linkedEntity`, `events`,
   * `name`, `emitsScope`, `listens`. `effects` is excluded —
   * atom-owned (use `listens` via a sibling trait instead).
   */
  traitOverrides?: Partial<Record<
    'ChangeOrderAppLayout' | 'ChangeOrderLedgerView' | 'ChangeOrderPanel',
    Pick<MakeTraitRefOpts, 'config' | 'linkedEntity' | 'events' | 'name' | 'emitsScope' | 'listens'>
  >>;
}

/** Per-orbital factory: builds the ChangeOrderPanelOrbital orbital with consumer params. */
export function stdConstructionPmChangeOrderPanelOrbital(params: StdConstructionPmChangeOrderPanelOrbitalParams = {}): OrbitalDefinition {
  const canonicalName = params.entityName ?? 'ChangeOrder';
  const collectionName = params.collection
    ?? (params.entityName ? `${params.entityName.toLowerCase()}s` : 'changeorders');
  const built = makeOrbitalWithUses({
    name: 'ChangeOrderPanelOrbital',
    uses: [
      {
        'from': 'std/behaviors/std-app-layout',
        'as': 'AppShell',
      },
      {
        'from': 'std/behaviors/std-change-order',
        'as': 'ChangeOrder',
      },
    ],
    entity: {
      name: canonicalName,
      collection: collectionName,
      persistence: params.persistence ?? 'persistent',
      fields: ((): EntityField[] => {
        const canonical: EntityField[] = [
          {
            'name': 'id',
            'type': 'string',
            'required': true,
          },
          {
            'name': 'coNumber',
            'type': 'string',
            'required': true,
          },
          {
            'name': 'description',
            'type': 'string',
            'required': true,
          },
          {
            'name': 'reason',
            'type': 'string',
            'default': '',
          },
          {
            'name': 'costImpact',
            'type': 'number',
            'default': 0,
          },
          {
            'name': 'scheduleImpactDays',
            'type': 'number',
            'default': 0,
          },
          {
            'name': 'status',
            'type': 'string',
            'default': 'draft',
            'values': [
              'draft',
              'pending-approval',
              'approved',
              'rejected',
              'executed',
            ],
          },
          {
            'name': 'requestedBy',
            'type': 'string',
            'default': '',
          },
          {
            'name': 'approvedBy',
            'type': 'string',
            'default': '',
          },
          {
            'name': 'requestedAt',
            'type': 'string',
            'default': '',
          },
          {
            'name': 'approvedAt',
            'type': 'string',
            'default': '',
          },
          {
            'name': 'pendingId',
            'type': 'string',
            'default': '',
          },
        ];
        const extras = params.fields ?? [];
        if (extras.length === 0) return canonical;
        const extraNames = new Set(extras.map((f) => f.name));
        return [...canonical.filter((f) => !extraNames.has(f.name)), ...extras];
      })(),
    } as Entity,
    traits: [
      makeTraitRef({
        'ref': 'AppShell.traits.AppLayout',
        'name': 'ChangeOrderAppLayout',
        'config': {
          'searchEvent': 'CHANGE_ORDER_SEARCH',
          'navItems': [
            {
              'icon': 'briefcase',
              'label': 'Projects',
              'href': '/projects',
            },
            {
              'label': 'RFIs',
              'href': '/rfis',
              'icon': 'message-circle',
            },
            {
              'label': 'Submittals',
              'href': '/submittals',
              'icon': 'file-text',
            },
            {
              'icon': 'edit',
              'href': '/change-orders',
              'label': 'Change Orders',
            },
          ],
          'notifications': [],
          'appName': 'Construction PM',
          'notificationClickEvent': 'CHANGE_ORDER_NOTIFICATIONS_OPEN',
          'contentTrait': '@trait.ChangeOrderPanel',
        },
        'events': {
          'SEARCH': 'CHANGE_ORDER_SEARCH',
          'NOTIFY_CLICK': 'CHANGE_ORDER_NOTIFICATIONS_OPEN',
        },
      }),
      rebindInlineTraitEntity({
        'name': 'ChangeOrderPanel',
        'category': 'interaction',
        'stateMachine': {
          'states': [
            {
              'name': 'composing',
              'isInitial': true,
            },
          ],
          'events': [
            {
              'key': 'INIT',
              'name': 'Initialize',
            },
          ],
          'transitions': [
            {
              'from': 'composing',
              'to': 'composing',
              'event': 'INIT',
              'effects': [
                [
                  'render-ui',
                  'main',
                  {
                    'className': 'max-w-6xl mx-auto w-full p-4',
                    'children': [
                      {
                        'direction': 'horizontal',
                        'children': [
                          {
                            'type': 'icon',
                            'name': 'edit',
                          },
                          {
                            'content': 'Change Orders',
                            'variant': 'h2',
                            'type': 'typography',
                          },
                        ],
                        'gap': 'sm',
                        'type': 'stack',
                        'align': 'center',
                      },
                      {
                        'type': 'divider',
                      },
                      '@trait.ChangeOrderLedgerView',
                    ],
                    'direction': 'vertical',
                    'gap': 'lg',
                    'type': 'stack',
                  },
                ],
              ],
            },
          ],
        },
        'scope': 'instance',
      } as never, 'ChangeOrder', canonicalName) as never,
      makeTraitRef({
        'ref': 'ChangeOrder.traits.ChangeOrderLedger',
        'name': 'ChangeOrderLedgerView',
        'config': {
          'title': 'Change Order Ledger',
        },
      }),
    ],
    pages: [
      {
        'name': 'ChangeOrdersPage',
        'path': '/change-orders',
        'traits': [
          {
            'ref': 'ChangeOrderAppLayout',
          },
          {
            'ref': 'ChangeOrderPanel',
          },
          {
            'ref': 'ChangeOrderLedgerView',
          },
        ],
      } as never,
    ],
  });
  type _OrbTrait = OrbitalDefinition["traits"][number];
  type _OrbPage = NonNullable<OrbitalDefinition["pages"]>[number];
  type _RefOverride = Pick<MakeTraitRefOpts, "config" | "linkedEntity" | "events" | "name" | "emitsScope" | "listens">;
  if (built.traits && params.traitOverrides !== undefined) {
    built.traits = (built.traits as _OrbTrait[]).map((t): _OrbTrait => {
      if (!t || typeof t !== "object") return t;
      const tr = t as TraitReference & { name?: string };
      // Match by name so inline traits (no `ref`) and
      // reference traits (with `ref`) both pick up the
      // override surface keyed on the trait's `name`.
      if (typeof tr.name !== "string") return t;
      const overrides = params.traitOverrides as Record<string, _RefOverride | undefined> | undefined;
      const override = overrides?.[tr.name];
      if (!override) return t;
      const merged: TraitReference = { ...tr };
      if (override.config !== undefined) merged.config = { ...(tr.config ?? {}), ...override.config };
      if (override.linkedEntity !== undefined) merged.linkedEntity = override.linkedEntity;
      if (override.events !== undefined) merged.events = { ...(tr.events ?? {}), ...override.events };
      if (override.name !== undefined) merged.name = override.name;
      if (override.emitsScope !== undefined) merged.emitsScope = override.emitsScope;
      if (override.listens !== undefined) merged.listens = override.listens;
      return merged;
    });
  }
  if (built.pages && params.pagePath !== undefined) {
    built.pages = (built.pages as _OrbPage[]).map((p, idx) => {
      if (!p || typeof p !== "object") return p;
      if (idx !== 0) return p;
      const out = { ...p } as _OrbPage & { path?: string };
      out.path = params.pagePath;
      return out;
    });
  }
  return built;
}

